    return n % 2 == 0 or (n - 2) % 2 == 0

def fix_spaces(text):
    result = []
    i = 0
    while i < len(text):
        if text[i] == ' ':
            start = i
            while i < len(text) and text[i] == ' ':
                i += 1
            space_count = i - start
            if space_count > 2:
                result.append('-')
            else:
                result.append('_' * space_count)
        else:
            result.append(text[i])
            i += 1
    return ''.join(result)

